import numpy as np
from collections import defaultdict
def compare_stats(inefficient,efficient):
    keys = inefficient.keys()
    keys2 = efficient.keys()
    superset = set(keys).union(set(keys2))
    per_scale_metrics = {'efficient':defaultdict(lambda :defaultdict(int)),'inefficient':defaultdict(lambda :defaultdict(int))}
    scales = []
    iters = []
    ki = 0
    max_inefficient_n = 0
    max_efficient_n = 0
    for k in superset:
        ki += 1
        scale = k[0]
        scales.append(scale)
        iters.append(k[1]+1)
        assert k in inefficient
        inefficient_n_k = inefficient[k]['n']
        max_inefficient_n = max(max_inefficient_n,inefficient_n_k)
        # if scale == 0:
        #     import ipdb; ipdb.set_trace()
        per_scale_metrics['inefficient'][scale]['time'] = per_scale_metrics['inefficient'][scale]['time'] + inefficient[k]['time']*inefficient_n_k
        per_scale_metrics['inefficient'][scale]['memory'] = max(per_scale_metrics['inefficient'][scale]['memory'],inefficient[k]['memory'])
        per_scale_metrics['inefficient'][scale]['iterations'] += int(k[0] == scale) * inefficient_n_k
        if k in efficient:
            efficient_n_k = efficient[k]['n']
            max_efficient_n = max(max_efficient_n,efficient_n_k)
            # if scale not in per_scale_metrics['efficient']:
            per_scale_metrics['efficient'][scale]['time'] += efficient[k]['time']*efficient_n_k
            per_scale_metrics['efficient'][scale]['memory'] = max(per_scale_metrics['efficient'][scale]['memory'],efficient[k]['memory'])
            per_scale_metrics['efficient'][scale]['iterations'] += int(k[0] == scale)*efficient_n_k
            
    scales = list(set(scales))
    iters = list(set(iters))
    for scale in scales:
        per_scale_metrics['efficient'][scale]['time'] = per_scale_metrics['efficient'][scale]['time']/max_efficient_n
        per_scale_metrics['inefficient'][scale]['time'] = per_scale_metrics['inefficient'][scale]['time']/max_inefficient_n
        
        per_scale_metrics['efficient'][scale]['iterations'] = per_scale_metrics['efficient'][scale]['iterations']/max_efficient_n
        
        per_scale_metrics['inefficient'][scale]['iterations'] = per_scale_metrics['inefficient'][scale]['iterations']/max_inefficient_n
    for scale in scales:
        print(scale,'efficient',per_scale_metrics['efficient'][scale],'inefficient',per_scale_metrics['inefficient'][scale])
    # print(ki)

    
    # save_plot(y,,savename,x=None)
    #====================================================================
    from matplotlib import pyplot as plt
    import os
    import colorful
    import dutils
    savedir = dutils.SAVE_DIR
    savename = os.path.join(savedir,'time_per_scale.png')
    print(os.path.abspath(savename))
    print(colorful.tan(f"saving {savename}"))
    efficient_times = [per_scale_metrics['efficient'][scale]['time'] for scale in scales] 
    inefficient_times = [per_scale_metrics['inefficient'][scale]['time'] for scale in scales]
    plt.figure()
    plt.plot(scales,efficient_times,label='efficient')
    plt.plot(scales,inefficient_times,label='inefficient')
    plt.title('time per scale')
    plt.legend()
    plt.show()
    plt.savefig(savename)
    plt.close()    
    # import ipdb; ipdb.set_trace()
    #====================================================================
    savename = os.path.join(savedir,'iter_per_scale.png')
    print(os.path.abspath(savename))
    print(colorful.tan(f"saving {savename}"))
    efficient_iters = [per_scale_metrics['efficient'][scale]['iterations'] for scale in scales] 
    inefficient_iters = [per_scale_metrics['inefficient'][scale]['iterations'] for scale in scales]
    plt.figure()
    plt.plot(scales,efficient_iters,label='efficient')
    plt.plot(scales,inefficient_iters,label='inefficient')
    plt.title('iterations per scale')
    plt.xticks(scales)
    # plt.yticks(iters)
    plt.legend()
    plt.show()
    plt.savefig(savename)
    plt.close()    
    #====================================================================
    savename = os.path.join(savedir,'max_mem_per_scale.png')
    print(os.path.abspath(savename))
    print(colorful.tan(f"saving {savename}"))
    efficient_mem = [per_scale_metrics['efficient'][scale]['memory'] for scale in scales] 
    inefficient_mem = [per_scale_metrics['inefficient'][scale]['memory'] for scale in scales]
    plt.figure()
    # plt.plot(scales,efficient_mem,label='efficient')
    # plt.plot(scales,inefficient_mem,label='inefficient')
    plt.plot(scales,
             (np.array(inefficient_mem) - np.array(efficient_mem))/(1024*1024),
             label='memory saved (mb)')
    plt.title('memory saved per scale (mb)')
    plt.xticks(scales)
    # plt.yticks(iters)
    # plt.legend()
    plt.show()
    plt.savefig(savename)
    plt.close()    
    
    print('TOTAL TIME TAKEN BY INEFFICIENT',sum(inefficient_times))
